local pg=0.001
local ph=0.001
local pi=0.0001

local bw={}
bw.__index=bw

function bw.new(cI,cL)
    assert(cI,"Missing argument #1: targetValue")
    cL=cL or {}
    return setmetatable({
        _targetValue=cI,
        _frequency=cL.frequency or 4,
        _dampingRatio=cL.dampingRatio or 1
    },bw)
end

function bw:step(F,gg)
    local pj=self._dampingRatio
    local gh=self._frequency*2*math.pi
    local dF=self._targetValue
    local gi=F.value
    local gj=F.velocity or 0
    local ct=gi-dF
    local gk=math.exp(-pj*gh*gg)
    local gl,gm

    if pj==1 then
        gl=(ct*(1+gh*gg)+gj*gg)*gk+dF
        gm=(gj*(1-gh*gg)-ct*gh*gh*gg)*gk
    elseif pj<1 then
        local pk=math.sqrt(1-pj*pj)
        local k2=math.cos(gh*pk*gg)
        local pl=math.sin(gh*pk*gg)
        local eP
        if pk>pi then
            eP=pl/pk
        else
            local hD=gg*gh
            eP=hD+(hD*hD*pk*pk*pk*pk/20-pk*pk)*hD*hD*hD/6
        end
        local ed
        if gh*pk>pi then
            ed=pl/(gh*pk)
        else
            local dG=gh*pk
            ed=gg+(gg*gg*dG*dG*dG*dG/20-dG*dG)*gg*gg*gg/6
        end
        gl=(ct*(k2+pj*eP)+gj*ed)*gk+dF
        gm=(gj*(k2-eP*pj)-ct*eP*gh)*gk
    else
        local pk=math.sqrt(pj*pj-1)
        local pm=-gh*(pj-pk)
        local pn=-gh*(pj+pk)
        local po=(gj-ct*pm)/(2*gh*pk)
        local pp=ct-po
        local pq=pp*math.exp(pm*gg)
        local pr=po*math.exp(pn*gg)
        gl=pq+pr+dF
        gm=pq*pm+pr*pn
    end

    local p9=math.abs(gm)<pg and math.abs(gl-dF)<ph
    return {complete=p9,value=p9 and dF or gl,velocity=gm}
end

return bw
